import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Button,
  Modal,
  SearchTextInput,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
  useErpListSelection,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { sxService } from '../../../services/sx/sxService';
import type { BomDto } from '../../../services/sx/models';
import { bomPageLabels as labels } from '../../../constants/bomPageLabels';
import { formatDateLocal } from '../../../utils/format';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { openListRowMenu } from '../../../utils/openListRowMenu';
import { VoucherRowActionMenu, type VoucherRowMenuAction } from '../../../components/voucher-list';
import { ListUiSchemaEditorModal } from '../../../components/listUiSchema';
import { LIST_UI_SCHEMA_KIND } from '../../../types/catalogUiSchema';
import { useMesBomPermissions } from '../../../hooks/useMesPermissions';
import { CatalogDocumentHistory } from '../../../components/catalog';
import { mesDocumentTypes } from '../../../config/documentHistoryClients';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-bom';
const PAGE_ID = 'sx-bom';
const CATALOG_KIND = LIST_UI_SCHEMA_KIND.mesBom;
const showSchemaConfig = true;

const BomListPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const perms = useMesBomPermissions();
  const [reloadKey, setReloadKey] = useState(0);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<BomDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: BomDto } | null>(null);
  const [showSchemaEditor, setShowSchemaEditor] = useState(false);
  const [historyOpen, setHistoryOpen] = useState(false);
  const [deleteOpen, setDeleteOpen] = useState(false);
  const [deleting, setDeleting] = useState(false);

  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const selection = useErpListSelection({
    rows: items,
    totalCount: items.length,
    page: 1,
    pageSize: Math.max(items.length, 1),
    getRowId: r => r.id,
  });

  const anchor = selection.activeRow;

  const refresh = useCallback(() => {
    selection.clearActiveRow();
    setReloadKey(k => k + 1);
  }, [selection]);

  const handleSearch = useCallback(() => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      setReloadKey(k => k + 1);
    });
  }, [pulseSearch, searchDraft]);

  const navigateToRow = useCallback(
    (id: string, startInEditMode?: boolean) => {
      navigate(`/sx/bom/${id}`, {
        state: startInEditMode ? { startInEditMode: true } : undefined,
      });
    },
    [navigate],
  );

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      sxService
        .getBoms({ searchText: search || undefined })
        .then(data => {
          if (!cancelled) setItems(data);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, labels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [dispatch, reloadKey, search]);

  const handleRowMenuSelect = useCallback(
    (action: VoucherRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      if (action === 'view') navigateToRow(row.id);
      if (action === 'edit') navigateToRow(row.id, true);
    },
    [rowMenu?.row, navigateToRow],
  );

  const handleDelete = useCallback(async () => {
    if (!anchor) return;
    setDeleting(true);
    try {
      await sxService.deleteBom(anchor.id);
      dispatchAppToast(dispatch, { message: labels.deleteSuccess, type: 'success' });
      setDeleteOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, labels.deleteError),
        type: 'error',
      });
    } finally {
      setDeleting(false);
    }
  }, [anchor, dispatch, refresh]);

  const catalogToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: refresh,
      canAdd: perms.canCreate,
      onAdd: () => navigate('/sx/bom/them'),
      showEdit: Boolean(anchor),
      showView: Boolean(anchor),
      canHistory: Boolean(anchor && perms.canRead),
      canDelete: Boolean(anchor && perms.canDelete),
      selectedCount: anchor ? 1 : 0,
      onEdit: () => anchor && navigateToRow(anchor.id, true),
      onView: () => anchor && navigateToRow(anchor.id),
      onHistory: () => setHistoryOpen(true),
      onDelete: () => setDeleteOpen(true),
      ...(showSchemaConfig ? { onEditConfig: () => setShowSchemaEditor(true) } : {}),
    }),
    [refresh, navigate, perms, anchor, navigateToRow],
  );

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-search`,
        content: (
          <SearchTextInput
            label="Tìm kiếm"
            placeholder={labels.searchPlaceholder}
            value={searchDraft}
            onChange={setSearchDraft}
            onSearch={handleSearch}
            testId={`${TEST_ID}-search-text`}
          />
        ),
      },
    ],
    [searchDraft, handleSearch],
  );

  const listBody =
    !showTableLoading && items.length === 0 ? (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <i className="fas fa-inbox" />
        <p>{labels.empty}</p>
      </div>
    ) : !showTableLoading ? (
      <div className={erp.tableWrapper}>
        <table className={erp.table} data-testid={`${TEST_ID}-table`}>
          <thead>
            <tr>
              <th className={erp.colNo}>STT</th>
              <th>Mã BOM</th>
              <th>Sản phẩm</th>
              <th>ĐVT</th>
              <th className={erp.colRight}>SL chuẩn</th>
              <th>Hiệu lực từ</th>
              <th className={erp.colRight}>Số NVL</th>
              <th>Trạng thái</th>
            </tr>
          </thead>
          <tbody>
            {items.map((b, index) => (
              <tr
                key={b.id}
                data-testid={`${TEST_ID}-row-${b.id}`}
                className={selection.activeRow?.id === b.id ? erp.rowSelected : undefined}
                onDoubleClick={() => navigateToRow(b.id)}
                onContextMenu={e =>
                  openListRowMenu(e, b, selection.selectActiveRow, setRowMenu)
                }
                onClick={e => {
                  if (e.ctrlKey || e.metaKey) {
                    openListRowMenu(e, b, selection.selectActiveRow, setRowMenu);
                  }
                }}
              >
                <td className={erp.colNo}>{index + 1}</td>
                <td>
                  <button
                    type="button"
                    className={erp.codeLink}
                    onClick={() => navigateToRow(b.id)}
                  >
                    <code>{b.code}</code>
                  </button>
                </td>
                <td>{b.productName ?? b.productCode}</td>
                <td>{b.unitCode}</td>
                <td className={erp.colRight}>{b.quantity}</td>
                <td>{formatDateLocal(b.effectiveFrom)}</td>
                <td className={erp.colRight}>{b.lines?.length ?? 0}</td>
                <td>
                  <span className={b.isActive ? erp.tagSuccess : erp.tagDefault}>
                    {b.isActive ? 'Khả dụng' : 'Ngưng'}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-catalog-list-page
      data-catalog-kind={CATALOG_KIND}
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="catalog"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: labels.listTitle,
          titleIconClass: 'fas fa-list-alt',
          pageId: PAGE_ID,
        }}
        catalogToolbar={catalogToolbar}
        listTitle={labels.listSubtitle}
        listRowMenuHelp
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={8}
        footer={
          items.length > 0 ? (
            <div className={erp.paginationRow}>
              <span className={erp.totalCount}>Tổng: {items.length} BOM</span>
            </div>
          ) : undefined
        }
        modals={
          <>
            <VoucherRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={TEST_ID}
              showView={perms.canRead}
              showEdit={perms.canUpdate}
            />
            {showSchemaConfig ? (
              <ListUiSchemaEditorModal
                testIdPrefix={TEST_ID}
                catalogKind={CATALOG_KIND}
                isOpen={showSchemaEditor}
                onClose={() => setShowSchemaEditor(false)}
                onSaved={() => refresh()}
                sampleRow={items[0] as unknown as Record<string, unknown>}
              />
            ) : null}
            {anchor ? (
              <CatalogDocumentHistory
                testIdPrefix={TEST_ID}
                documentType={mesDocumentTypes.bom}
                documentId={anchor.id}
                documentCode={anchor.code}
                variant="inline"
                isOpen={historyOpen}
                onClose={() => setHistoryOpen(false)}
              />
            ) : null}
            <Modal
              isOpen={deleteOpen}
              onClose={() => !deleting && setDeleteOpen(false)}
              title="Xóa BOM"
            >
              <p>{labels.deleteConfirm}</p>
              {anchor ? <p><strong>{anchor.code}</strong></p> : null}
              <div className={erp.modalActions}>
                <Button variant="secondary" onClick={() => setDeleteOpen(false)} disabled={deleting}>
                  Hủy
                </Button>
                <Button variant="danger" onClick={handleDelete} loading={deleting}>
                  Xóa
                </Button>
              </div>
            </Modal>
          </>
        }
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default BomListPage;
